// spotless:off
package frc.robot.autos;

import edu.wpi.first.math.geometry.Pose2d;
import edu.wpi.first.math.geometry.Rotation2d;
import java.util.Map;
import java.util.OptionalInt;



/**
 * A class containing the name, start pose, end pose, and total time of every Choreo trajectory.
 * This prevents your code from referencing deleted or misspelled trajectories,
 * and removes the need for JSON parsing to load a trajectory's essential data.
 * DO NOT MODIFY THIS FILE YOURSELF! It is automatically generated by Choreo.
 */
public record ChoreoTraj(
    String name,
    OptionalInt segment,
    double totalTimeSecs,
    Pose2d initialPoseBlue,
    Pose2d endPoseBlue
) {
    public static final ChoreoTraj CanadianDepot_FirstPass = new ChoreoTraj(
        "CanadianDepot_FirstPass",
        OptionalInt.empty(),
        4.43049,
        new Pose2d(6.34, 7.55, Rotation2d.fromRadians(-1.5708)),
        new Pose2d(3.96548, 5.61758, Rotation2d.fromRadians(1.99499))
    );
    public static final ChoreoTraj CanadianHuman_FirstPass = new ChoreoTraj(
        "CanadianHuman_FirstPass",
        OptionalInt.empty(),
        4.58063,
        new Pose2d(6.39331, 0.60333, Rotation2d.fromRadians(1.5708)),
        new Pose2d(3.97757, 2.46514, Rotation2d.fromRadians(-1.99499))
    );
    public static final ChoreoTraj CanadianHuman_SeconPass = new ChoreoTraj(
        "CanadianHuman_SeconPass",
        OptionalInt.empty(),
        4.34281,
        new Pose2d(6.39331, 0.60333, Rotation2d.fromRadians(1.5708)),
        new Pose2d(3.99296, 2.29589, Rotation2d.fromRadians(-2.40878))
    );

    /**
     * A map between trajectory names and their corresponding data.
     * This allows for trajectory data to be looked up with strings during runtime.
     */
    public static final Map<String, ChoreoTraj> ALL_TRAJECTORIES = Map.ofEntries(
        Map.entry("CanadianDepot_FirstPass", CanadianDepot_FirstPass),
        Map.entry("CanadianHuman_FirstPass", CanadianHuman_FirstPass),
        Map.entry("CanadianHuman_SeconPass", CanadianHuman_SeconPass)
    );

    /**
     * Looks up the ChoreoTraj segment of the given overall ChoreoTraj.
     * WARNING: will raise an exception if not called with a valid segment index.
     */
    public ChoreoTraj segment(int segment) {
        var traj = ChoreoTraj.ALL_TRAJECTORIES.get(this.name + "$" + segment);
        if (traj == null) {
            throw new NullPointerException("Trajectory " + this.name + " does not have segment #" + segment + ".");
        }
        return traj;
    }
    
}
// spotless:on
